        Table(
            Tr(Td(f"Total number of {what}:"), Td(f"{total_jobs}")),
            Tr(
                Td("Most common state:"),
                Td(
                    f"{most_common_state.name} ({most_common_count} {what}, {state_percentages[most_common_state]:.2f}%)"
                ),
            ),
            Tr(Td(f"Running {what}:"), Td(f"{running_count}")),
